s($,"btH","b89",()=>A.iz(new A.aQk(),"You built a road! Your stones form an unbroken path from one edge to the opposite edge. That's how you win at Tak.",B.VT,B.Q1,null,null,"tutorial_1","Place a stone to complete the road.",null,B.dS,"Complete a road from top to bottom.","Building a Road",B.bh))
s($,"btI","b8a",()=>A.iz(new A.aQl(),"Your wall blocks their road! Walls are powerful blockers, but remember they can't be part of your road. Use them strategically.",B.Y8,B.Q_,null,null,"tutorial_2","Select the wall piece type, then place it to block Black.",null,B.o4,"Use a wall to block an opponent's road.","Standing Stones (Walls)",B.bh))
s($,"btJ","b8b",()=>A.iz(new A.aQm(),"The wall is now flat \u2014 and your road is complete! The Capstone is essential for breaking through defenses.",B.WO,B.PX,null,null,"tutorial_3","Move the Capstone onto the wall to flatten it.",null,B.dS,"Use the Capstone to flatten a wall.","The Capstone",B.bh))
s($,"btK","b8c",()=>A.iz(new A.aQn(),"Pieces can move onto empty cells or onto other pieces (creating stacks). Moving lets you reposition without using new pieces from your supply.",B.XW,B.v8,null,null,"tutorial_4","Move your stone onto the adjacent black piece.",null,B.we,"Learn to move pieces on the board.","Moving a Single Piece",B.bh))
s($,"btL","b8d",()=>A.iz(new A.aQo(),"The whole stack moved together! Controlling your opponent's pieces in stacks is a powerful tactic. Only the top piece determines the stack's color for roads.",B.VY,B.v8,null,null,"tutorial_5","Move the stack to demonstrate control.",null,B.o4,"Understand stack control.","Stacks and Control",B.bh))
s($,"btM","b8e",()=>A.iz(new A.aQp(),"Excellent! You can only carry up to the board size (5 on a 5\xd75 board), even from taller stacks. Use this to spread influence across the board!",B.Yv,B.PZ,null,null,"tutorial_6","Spread the stack across the board.",null,B.o4,"Learn about carry limits and dropping pieces.","Stack Movement & Carry Limit",B.bh))
s($,"btN","b8f",()=>A.iz(new A.aQq(),"The opening rule is easy to forget! Some players place the opponent's piece in a corner (giving them little value), others place it centrally (creating interesting positions).",B.X2,B.v7,null,null,"tutorial_7","Place a Black flat stone (your opponent's color).",null,B.we,"Learn the special first-turn rule.","The Opening Rule",B.bh))
s($,"btO","b8g",()=>A.iz(new A.aQr(),"You won by flat count! You had more flat stones showing on top. Walls block roads but hurt your flat count \u2014 use them wisely.",B.VO,B.PY,null,null,"tutorial_8","Place your last stone to fill the board and win!",null,B.dS,"Learn the alternative win condition.","Winning by Flat Count",B.bh))
s($,"btP","b8h",()=>A.iz(new A.aQs(),"When pieces run low, every placement matters. Sometimes it's better to move existing pieces rather than place new ones. Watch your supply \u2014 and your opponent's!",B.Vk,B.v7,null,null,"tutorial_9","Place your last piece to end the game.",null,B.dS,"Manage your limited piece supply.","Running Out of Pieces",B.bh))
s($,"bta","b7L",()=>A.iz(new A.aQ6(),"Capturing stacks turns enemy pieces into your road. Control is everything in Tak!",B.TF,B.v9,null,null,"puzzle_6","Win in 1 move. Capture the enemy stack to complete your road!",B.pk,B.dS,"Capture a stack to complete your road!","Capture and Win",B.bY))
s($,"btb","b7M",()=>A.iz(new A.aQ7(),"Spreading over enemy pieces converts them to your road. A powerful finishing move!",B.XC,B.Q0,null,null,"puzzle_7","Win in 1 move. Spread over the enemy pieces to complete your road!",B.pk,B.dS,"Spread your stack to complete your road!","The Spread",B.bY))
s($,"btc","b7N",()=>A.iz(new A.aQ8(),"The Capstone flattens walls that would stop any other piece. Master this technique!",B.UG,B.v9,null,null,"puzzle_9","Win in 1 move. Flatten the wall to complete your road!",B.pk,B.dS,"Use your Capstone to flatten and win!","Capstone Tactics",B.bY))
s($,"bt7","b7I",()=>A.iz(new A.aQ3(),"The fork is the most powerful tactic \u2014 threaten two roads, win with one!",B.YZ,B.PW,null,null,"puzzle_10","Win in 2 moves. Create a double threat!",B.pl,B.XS,"Create a fork Black cannot escape!","The Fork",B.bY))
s($,"bt8","b7J",()=>A.iz(new A.aQ4(),"Three precise moves! The setup placement was crucial \u2014 moving the Capstone first would have failed. Patience and planning win in Tak.",B.YC,B.v6,B.n8,"Don't move the Capstone yet. Create a threat on Column 3 first...","puzzle_11","Win in 3 moves. Every move must be precise!",B.pl,B.vR,"A three-move forced win \u2014 if you find the right sequence!","The Crucible",B.bY))
s($,"bt9","b7K",()=>A.iz(new A.aQ5(),"Perfect execution. You forced both replies, then used the Capstone break to finish the only winning road.",B.WF,B.v6,B.Ok,"Start with the quiet placement at (2,3). The winning break comes only after Black's forced wall responses.","puzzle_12","Win in 3 moves. Every response is forced.",B.pl,B.vR,"Break a fortified defense with a precise three-move sequence.","Iron Causeway",B.bY))
